import{_ as a,c as e,o as l,a4 as t}from"./chunks/framework.HaEZziQ1.js";const r="/FrontEndLearnNotes/assets/wiresharklayout.BrOKb4c4.png",s="/FrontEndLearnNotes/assets/wireshareprotocal.X0k5uXn3.jpg",i="/FrontEndLearnNotes/assets/wireshareshow.Clqn6nQS.jpg",p="/FrontEndLearnNotes/assets/tcpconnect.BpWFKYNC.png",o="/FrontEndLearnNotes/assets/Wiresharkseven.Dr9evC09.jpg",n="/FrontEndLearnNotes/assets/tcpinfo.glyGDpp0.jpg",E=JSON.parse('{"title":"抓包工具调试","description":"","frontmatter":{},"headers":[],"relativePath":"Document/DevDebug/抓包工具调试.md","filePath":"Document/DevDebug/抓包工具调试.md","lastUpdated":1709668918000}'),h={name:"Document/DevDebug/抓包工具调试.md"},c=t(`<h1 id="抓包工具调试" tabindex="-1">抓包工具调试 <a class="header-anchor" href="#抓包工具调试" aria-label="Permalink to &quot;抓包工具调试&quot;">​</a></h1><p>抓包技能：<a href="https://juejin.cn/post/7140040425129115684" target="_blank" rel="noreferrer">https://juejin.cn/post/7140040425129115684</a></p><p>抓包工具：Fiddler/HTTPDebugger/Charles【PC】、HttpCarry【Android】、Stream【iphone】</p><h2 id="fiddler" tabindex="-1">Fiddler <a class="header-anchor" href="#fiddler" aria-label="Permalink to &quot;Fiddler&quot;">​</a></h2><p>待定</p><h2 id="whistle" tabindex="-1">whistle <a class="header-anchor" href="#whistle" aria-label="Permalink to &quot;whistle&quot;">​</a></h2><p><strong>官方文档</strong>：<a href="https://wproxy.org/whistle/" target="_blank" rel="noreferrer">https://wproxy.org/whistle/</a></p><p><strong>GitHub</strong>：<a href="https://github.com/avwo/whistle" target="_blank" rel="noreferrer">https://github.com/avwo/whistle</a></p><p>介绍：于Node实现的跨平台web调试代理工具，类似的工具有Windows平台上的Fiddler，主要用于查看、修改HTTP、HTTPS、Websocket的请求、响应，也可以作为HTTP代理服务器使用，不同于Fiddler通过断点修改请求响应的方式，whistle采用的是类似配置系统hosts的方式，一切操作都可以通过配置实现，支持域名、路径、正则表达式、通配符、通配路径等多种匹配方式，且可以通过Node模块扩展功能</p><hr><h3 id="whistle的使用" tabindex="-1">whistle的使用 <a class="header-anchor" href="#whistle的使用" aria-label="Permalink to &quot;whistle的使用&quot;">​</a></h3><p>通过https访问仅支持http的网站</p><p>场景：本地开发用https访问</p><p>本地开发时，假设服务启动在127.0.0.1:3000上，它可能只支持http访问，不支持https访问。但是有一些API是只能在https使用的（例如navigator定位相关）。</p><p>如果你想使用https访问127.0.0.1:3000，你只需要配置这样的代理即可：</p><p><a href="https://127.0.0.1:3000/" target="_blank" rel="noreferrer">https://127.0.0.1:3000/</a> <a href="http://127.0.0.1:3000/" target="_blank" rel="noreferrer">http://127.0.0.1:3000/</a></p><p>配置应该写在如图所示的地方：</p><p>你访问<a href="https://127.0.0.1:3000/%E6%97%B6%EF%BC%8C%E5%B0%B1%E4%BC%9A%E4%BB%A5https%E6%96%B9%E5%BC%8F%E8%AE%BF%E9%97%AE%E5%88%B0%E4%BD%A0%E7%9A%84%E5%89%8D%E7%AB%AF%E6%9C%8D%E5%8A%A1%E5%95%A6%E3%80%82" target="_blank" rel="noreferrer">https://127.0.0.1:3000/时，就会以https方式访问到你的前端服务啦。</a></p><p>原理</p><p>whistle服务和你的前端服务是通过http连接的，你的浏览器和你的whistle服务是通过https连接的。whistle作为中间人，只是转发、透传。</p><p>通过线上域名访问你的本地服务</p><p>场景一：前端代码里可能有域名判断。以前，我们可能得在代码里这么写：</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#C678DD;">if</span><span style="color:#ABB2BF;"> ([</span><span style="color:#98C379;">&#39;127.0.0.1&#39;</span><span style="color:#ABB2BF;">, </span><span style="color:#98C379;">&#39;localhost&#39;</span><span style="color:#ABB2BF;">].</span><span style="color:#61AFEF;">includes</span><span style="color:#ABB2BF;">(</span><span style="color:#E5C07B;">window</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">location</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">host</span><span style="color:#ABB2BF;">)) {</span></span>
<span class="line"></span>
<span class="line"><span style="color:#ABB2BF;">} </span><span style="color:#C678DD;">else</span><span style="color:#C678DD;"> if</span><span style="color:#ABB2BF;"> (</span><span style="color:#E5C07B;">window</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">location</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">host</span><span style="color:#56B6C2;"> ===</span><span style="color:#98C379;"> &#39;online.com&#39;</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>有什么后果？线上分支测试不到。你本地只测试了第一个分支，但是第二个分支没法测。</p><p>场景二：跨域问题</p><p>有时候代码依赖后端API，但是后端开发没给127.0.0.1域名配置CORS头，只允许同域名的来源访问API。本地开发时用127.0.0.1发请求会报跨域问题。</p><p>场景三：切换线上数据、测试数据、mock数据</p><p>我们代码中发请求，可能都是对服务器线上域名发请求。这样切换测试数据、mock数据不太方便。</p><p>解决</p><p>你可以配置代理，将线上域名转到本地开发服务器上（或者转到测试环境、mock数据）。这样虽然浏览器认为你的域名是线上服务，但展示内容其实是你的开发服务器（请求到数据也都是测试环境或mock数据）。</p><p>假设你的本地服务器是127.0.0.1:3000，线上服务器是online.com，你可以配置代理：</p><p><a href="http://online.com/" target="_blank" rel="noreferrer">http://online.com/</a> <a href="http://127.0.0.1:3000/" target="_blank" rel="noreferrer">http://127.0.0.1:3000/</a></p><p>原理</p><p>你的浏览器通过<a href="http://online.com/%E8%AE%BF%E9%97%AE%E4%BD%A0%E7%9A%84whistle%E6%9C%8D%E5%8A%A1%EF%BC%8Cwhistle%E6%9C%8D%E5%8A%A1%E8%AE%BF%E9%97%AEhttp://127.0.0.1:3000/%E3%80%82whistle%E4%BD%9C%E4%B8%BA%E4%B8%AD%E9%97%B4%E4%BA%BA%EF%BC%8C%E5%8F%AA%E6%98%AF%E8%BD%AC%E5%8F%91%E3%80%81%E9%80%8F%E4%BC%A0%E3%80%82" target="_blank" rel="noreferrer">http://online.com/访问你的whistle服务，whistle服务访问http://127.0.0.1:3000/。whistle作为中间人，只是转发、透传。</a></p><p>解决跨域问题</p><p>场景：某个别人的网站报错跨域bug</p><p>如果你访问一些网站时崩溃了，那个网站没人修，但你着急用，你可以找到报错的域名，通过whistle解决跨域问题。</p><p>解决</p><p>有2种方法（下面2行分别是一种），可以都试一下，看哪个好用就用哪个，记得把域名改成跨域请求的域名。</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">i.snssdk.com</span><span style="color:#98C379;"> resCors://enable</span></span>
<span class="line"><span style="color:#61AFEF;">mcs.snssdk.com</span><span style="color:#98C379;"> resCors://</span><span style="color:#E5C07B;">*</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>参考whistle的resCors语法。</p><p>原理</p><p>跨域，是浏览器行为。其实发生跨域时，请求已经发出，响应也已经收到，但是浏览器发现服务器不允许跨域，就不展示给用户了。</p><p>只要我们让whistle做一个「中间人」，修改响应头，给跨域头通通加上，再把Response返回给浏览器，就解决跨域问题了。</p><p>修改API响应内容</p><p>场景：看看掘金双Lv8 Logo是什么样子</p><p>如果我们想修改掘金API返回结果怎么办？</p><p>改一些UI逻辑，改DOM可不容易，你可能还要去其他人那里找现成的来复制。</p><p>不如干脆直接，改请求结果！那么页面自动按照请求结果渲染，如下图：</p><p>解决</p><p>详见whistle的resBody语法。</p><p>原理</p><p>whistle作为中间人，用你提供的Response Body替换了掘金服务器的Response Body。</p><p>启动本地静态资源服务器</p><p>场景：本地预览编译结果</p><p>有时候，我们编译好了，想测试一下编译产物是否正常。难道需要部署完才能测试吗？</p><p>大可不必，启动whistle，把某个域名解析到你的某个文件目录，那么就可以直接用HTTP协议访问啦。</p><p>解决</p><p>详见whistle的file语法。</p><p>原理</p><p>whistle作为中间人，用你提供的文件路径，作为Response，返回给了浏览器。</p><h2 id="wireshark-抓包工具的使用" tabindex="-1">wireshark 抓包工具的使用 <a class="header-anchor" href="#wireshark-抓包工具的使用" aria-label="Permalink to &quot;wireshark 抓包工具的使用&quot;">​</a></h2><p>参考珠峰教学文章笔记：<a href="http://www.zhufengpeixun.com/strong/html/12.NetWork-3.html#t01.%20wireshark%E6%9C%89%E4%BB%80%E4%B9%88%E7%94%A8" target="_blank" rel="noreferrer">http://www.zhufengpeixun.com/strong/html/12.NetWork-3.html#t01. wireshark有什么用</a></p><h3 id="_1-wireshark有什么用" tabindex="-1">1. wireshark有什么用 <a class="header-anchor" href="#_1-wireshark有什么用" aria-label="Permalink to &quot;1. wireshark有什么用&quot;">​</a></h3><ol><li>分析网络底层协议</li><li>解决网络故障问题</li><li>找寻网络安全问题</li></ol><h3 id="_2-安装" tabindex="-1">2. 安装 <a class="header-anchor" href="#_2-安装" aria-label="Permalink to &quot;2. 安装&quot;">​</a></h3><ul><li><a href="https://www.wireshark.org/download.html" target="_blank" rel="noreferrer">download</a></li><li><a href="http://wiresharkbook.com/" target="_blank" rel="noreferrer">wiresharkbook</a></li></ul><h3 id="_3-快速抓包" tabindex="-1">3. 快速抓包 <a class="header-anchor" href="#_3-快速抓包" aria-label="Permalink to &quot;3. 快速抓包&quot;">​</a></h3><ul><li>初始化界面</li><li>选择网卡</li><li>停止抓包</li><li>保存数据包</li></ul><h3 id="_4-界面" tabindex="-1">4. 界面 <a class="header-anchor" href="#_4-界面" aria-label="Permalink to &quot;4. 界面&quot;">​</a></h3><p><img src="`+r+'" alt="抓包过滤器"></p><ul><li>标题栏</li><li>主菜单栏</li><li>工具栏</li><li>数据包过滤栏</li><li>数据包列表区</li><li>数据包详细区</li><li>数据包字节区</li><li>数据包统计区</li></ul><h3 id="_5-过滤器设置" tabindex="-1">5. 过滤器设置 <a class="header-anchor" href="#_5-过滤器设置" aria-label="Permalink to &quot;5. 过滤器设置&quot;">​</a></h3><h4 id="_5-1-抓包过滤器" tabindex="-1">5.1 抓包过滤器 <a class="header-anchor" href="#_5-1-抓包过滤器" aria-label="Permalink to &quot;5.1 抓包过滤器&quot;">​</a></h4><p><img src="'+s+'" alt="抓包过滤器"></p><h5 id="_5-1-1-语法" tabindex="-1">5.1.1 语法 <a class="header-anchor" href="#_5-1-1-语法" aria-label="Permalink to &quot;5.1.1 语法&quot;">​</a></h5><p>协议+方向+类型+值</p><ul><li>HOST net port host</li><li>方向 src、dst、src and dst、src or dst</li><li>协议 ether ip tcp udp http ftp</li><li>逻辑运算符 &amp;&amp; || !</li></ul><h5 id="_5-1-2-例子" tabindex="-1">5.1.2 例子 <a class="header-anchor" href="#_5-1-2-例子" aria-label="Permalink to &quot;5.1.2 例子&quot;">​</a></h5><ul><li>src host 192.168.1.1 &amp;&amp; dst port 80 抓取来源地址为192.168.1.1，并且目的为80端口的流量</li><li>host 192.168.1.1|| host host 192.168.1.2 抓取192.168.1.1或192.168.1.2的流量</li><li>!broadcast 不抓取广播包</li></ul><h6 id="_5-1-2-1-过滤mac" tabindex="-1">5.1.2.1 过滤MAC <a class="header-anchor" href="#_5-1-2-1-过滤mac" aria-label="Permalink to &quot;5.1.2.1 过滤MAC&quot;">​</a></h6><ul><li>ether host 00:00:00:00:00:00 网卡主机</li><li>ether src host 00:00:00:00:00:00 来源MAC</li><li>ether dst host 00:00:00:00:00:00 目标MAC</li></ul><h6 id="_5-1-2-2-过滤ip" tabindex="-1">5.1.2.2 过滤IP <a class="header-anchor" href="#_5-1-2-2-过滤ip" aria-label="Permalink to &quot;5.1.2.2 过滤IP&quot;">​</a></h6><ul><li>host 192.168.1.1</li><li>src host 192.168.1.1</li><li>det host 192.168.1.1</li></ul><h6 id="_5-1-2-3-过滤端口" tabindex="-1">5.1.2.3 过滤端口 <a class="header-anchor" href="#_5-1-2-3-过滤端口" aria-label="Permalink to &quot;5.1.2.3 过滤端口&quot;">​</a></h6><ul><li>port 80</li><li>!port 80</li><li>dst port 80</li><li>src port 80</li></ul><h6 id="_5-1-2-4-过滤协议" tabindex="-1">5.1.2.4 过滤协议 <a class="header-anchor" href="#_5-1-2-4-过滤协议" aria-label="Permalink to &quot;5.1.2.4 过滤协议&quot;">​</a></h6><ul><li>arp</li><li>tcp</li></ul><h6 id="_5-1-2-5-综合过滤" tabindex="-1">5.1.2.5 综合过滤 <a class="header-anchor" href="#_5-1-2-5-综合过滤" aria-label="Permalink to &quot;5.1.2.5 综合过滤&quot;">​</a></h6><ul><li>host 192.168.1.100 &amp;&amp; port 8080</li></ul><h4 id="_5-2-显示过滤器" tabindex="-1">5.2 显示过滤器 <a class="header-anchor" href="#_5-2-显示过滤器" aria-label="Permalink to &quot;5.2 显示过滤器&quot;">​</a></h4><p>显示过滤器：对捕捉到的数据包依据协议或包的内容进行过滤 <img src="'+i+'" alt="抓包过滤器"></p><h5 id="_5-2-1-语法" tabindex="-1">5.2.1 语法 <a class="header-anchor" href="#_5-2-1-语法" aria-label="Permalink to &quot;5.2.1 语法&quot;">​</a></h5><ul><li><p>比较操作符 == != &gt; &lt; &gt;= &lt;=</p></li><li><p>逻辑操作符 and or xor(有且仅有一个条件被满足) not</p></li><li><p>IP地址 ip addr ip.src ip.dst</p></li><li><p>端口过滤 tcp.port tcp.srcport tcp.dstport tcp.flags.syn tcp.flag.ack</p></li><li><p>协议过滤 arp ip icmp udp tcp bootp dns</p></li></ul><h5 id="_5-2-2-案例" tabindex="-1">5.2.2 案例 <a class="header-anchor" href="#_5-2-2-案例" aria-label="Permalink to &quot;5.2.2 案例&quot;">​</a></h5><h6 id="_5-2-2-1-过滤ip" tabindex="-1">5.2.2.1 过滤IP <a class="header-anchor" href="#_5-2-2-1-过滤ip" aria-label="Permalink to &quot;5.2.2.1 过滤IP&quot;">​</a></h6><ul><li><p>ip.addr == 192.168.0.1</p></li><li><p>ip.src == 192.168.0.1</p></li><li><p>ip.dst == 192.168.0.1</p></li><li><p>ip.src == 192.168.0.1 and ip.dst == 192.168.0.1</p></li></ul><h6 id="_5-2-2-2-过滤端口" tabindex="-1">5.2.2.2 过滤端口 <a class="header-anchor" href="#_5-2-2-2-过滤端口" aria-label="Permalink to &quot;5.2.2.2 过滤端口&quot;">​</a></h6><ul><li>tcp.port == 80</li><li>tcp.srcport == 80</li><li>tcp.dstport == 80</li><li>tcp.flags.sync == 1</li></ul><h6 id="_5-2-2-3-过滤协议" tabindex="-1">5.2.2.3 过滤协议 <a class="header-anchor" href="#_5-2-2-3-过滤协议" aria-label="Permalink to &quot;5.2.2.3 过滤协议&quot;">​</a></h6><ul><li>arp</li><li>tcp</li><li>udp</li><li>not http</li><li>not arp</li></ul><h6 id="_5-2-2-4-案例" tabindex="-1">5.2.2.4 案例 <a class="header-anchor" href="#_5-2-2-4-案例" aria-label="Permalink to &quot;5.2.2.4 案例&quot;">​</a></h6><ul><li>ip.src == 192.168.0.1 and tcp.dstport == 80</li><li>ip.addr == 192.168.0.1 and udp.port == 60000</li></ul><h3 id="_6-三次握手" tabindex="-1">6. 三次握手 <a class="header-anchor" href="#_6-三次握手" aria-label="Permalink to &quot;6. 三次握手&quot;">​</a></h3><p><img src="'+p+'" alt="抓包过滤器"></p><h4 id="_7-wireshark与对应的osi七层模型" tabindex="-1">7. Wireshark与对应的OSI七层模型 <a class="header-anchor" href="#_7-wireshark与对应的osi七层模型" aria-label="Permalink to &quot;7. Wireshark与对应的OSI七层模型&quot;">​</a></h4><p><img src="'+o+'" alt="Wiresharkseven"></p><h4 id="tcp包具体内容" tabindex="-1">TCP包具体内容 <a href="http://www.zhufengpeixun.com/strong/html/12.NetWork-3.html#t22TCP%E5%8C%85%E5%85%B7%E4%BD%93%E5%86%85%E5%AE%B9" target="_blank" rel="noreferrer">#</a> <a class="header-anchor" href="#tcp包具体内容" aria-label="Permalink to &quot;TCP包具体内容 [#](http://www.zhufengpeixun.com/strong/html/12.NetWork-3.html#t22TCP包具体内容)&quot;">​</a></h4><p><img src="'+n+'" alt="tcpinfo"></p><h4 id="_8-参考" tabindex="-1">8.参考 <a class="header-anchor" href="#_8-参考" aria-label="Permalink to &quot;8.参考&quot;">​</a></h4><ul><li><a href="https://www.cnblogs.com/TankXiao/archive/2012/10/10/2711777.html" target="_blank" rel="noreferrer">wireshark</a></li></ul>',111),d=[c];function u(b,m,_,k,B,w){return l(),e("div",null,d)}const g=a(h,[["render",u]]);export{E as __pageData,g as default};
